export function isReverse(context: any): boolean;

export default class Connect {
    static $inject: string[];
    /**
     * @param eventBus
     * @param dragging
     * @param modeling
     * @param rules
     */
    constructor(eventBus: EventBus, dragging: Dragging, modeling: Modeling, rules: Rules);
    /**
     * Start connect operation.
     *
     * @param event
     * @param start
     * @param connectionStart
     * @param autoActivate
     */
    start: (event: MouseEvent | TouchEvent, start: Element, connectionStart?: Point, autoActivate?: boolean) => void;
}

type Element = import("../../model/Types.js").Element;
type Point = import("../../util/Types.js").Point;
type Dragging = import("../dragging/Dragging.js").default;
type EventBus = import("../../core/EventBus.js").default;
type Modeling = import("../modeling/Modeling.js").default;
type Rules = import("../rules/Rules.js").default;